import React, { useState } from 'react';

const groups = [
  {
    icon: '☁️', title: 'Cloud Platforms', accent: '#0078d4',
    skills: ['AWS Cloud Practitioner', 'Azure AZ-900', 'Azure AZ-104', 'Microsoft Entra ID', 'Azure Active Directory'],
  },
  {
    icon: '🔒', title: 'Security & Compliance', accent: '#c23b22',
    skills: ['ISC2 Certified in Cybersecurity', 'Microsoft Defender', 'Microsoft Purview', 'Security Incident Response'],
  },
  {
    icon: '💻', title: 'Endpoint & Device Management', accent: '#107c10',
    skills: ['Microsoft Intune', 'SCCM', 'Knox Management', 'Flexera Snow', 'Windows', 'iOS', 'Linux'],
  },
  {
    icon: '📊', title: 'Microsoft 365 & Monitoring', accent: '#d83b01',
    skills: ['Teams Admin', 'Exchange', 'Purview', 'AppDynamics', 'Zscaler ELK', 'Thousand Eyes'],
  },
  {
    icon: '🏢', title: 'Business Applications', accent: '#5c2d91',
    skills: ['Microsoft FinOps', 'Dynamics 365 Retail', 'SAP C/4HANA', 'EFTPOS / POS Systems', 'Farmlands Pro'],
  },
  {
    icon: '⚙️', title: 'Scripting & Automation', accent: '#005b70',
    skills: ['PowerShell', 'Active Directory', 'ITIL Service Management', 'License Management', 'Network Configuration'],
  },
];

const certifications = [
  { name: 'AWS Cloud Practitioner', issuer: 'Amazon Web Services', color: '#FF9900' },
  { name: 'Azure Fundamentals', issuer: 'Microsoft · AZ-900', color: '#0078d4' },
  { name: 'Azure Administrator', issuer: 'Microsoft · AZ-104', color: '#0078d4' },
  { name: 'Certified in Cybersecurity', issuer: 'ISC2 · CC', color: '#1a1a2e' },
];

const Skills: React.FC = () => {
  const [activeGroup, setActiveGroup] = useState<string | null>(null);

  return (
    <div style={{ padding: '28px 32px', overflowY: 'auto', background: '#fafafa', minHeight: '100%' }}>

      {/* Page title */}
      <div style={{ marginBottom: 28 }}>
        <h2 style={{ fontSize: 20, color: '#111', fontWeight: 'bold', marginBottom: 4 }}>
          Skills &amp; Certifications
        </h2>
        <div style={{ height: 3, width: 48, background: '#000080' }} />
      </div>

      {/* Certification badges row */}
      <div style={{ marginBottom: 32 }}>
        <p style={{ fontSize: 10, textTransform: 'uppercase', letterSpacing: 2, color: '#888', marginBottom: 12 }}>
          Certifications
        </p>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          {certifications.map(cert => (
            <div key={cert.name} style={{
              display: 'flex', alignItems: 'center', gap: 10,
              background: '#fff',
              border: '1px solid #e0e0e0',
              borderLeft: `4px solid ${cert.color}`,
              padding: '10px 16px',
              minWidth: 180,
              boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
            }}>
              <div>
                <div style={{ fontSize: 12, fontWeight: 'bold', color: '#111', marginBottom: 2 }}>{cert.name}</div>
                <div style={{ fontSize: 10, color: '#777' }}>{cert.issuer}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Skills grid */}
      <div style={{ marginBottom: 28 }}>
        <p style={{ fontSize: 10, textTransform: 'uppercase', letterSpacing: 2, color: '#888', marginBottom: 12 }}>
          Technical Skills
        </p>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
          {groups.map(g => (
            <div
              key={g.title}
              onClick={() => setActiveGroup(activeGroup === g.title ? null : g.title)}
              style={{
                background: '#fff',
                border: '1px solid #e0e0e0',
                borderLeft: `4px solid ${g.accent}`,
                padding: '14px 16px',
                cursor: 'pointer',
                boxShadow: activeGroup === g.title ? `0 2px 12px rgba(0,0,0,0.1)` : '0 1px 3px rgba(0,0,0,0.05)',
                transition: 'box-shadow 0.2s',
              }}
            >
              {/* Group header */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: activeGroup === g.title ? 12 : 0 }}>
                <span style={{ fontSize: 16 }}>{g.icon}</span>
                <span style={{ fontSize: 12, fontWeight: 'bold', color: '#222' }}>{g.title}</span>
                <span style={{ marginLeft: 'auto', fontSize: 10, color: '#aaa' }}>
                  {g.skills.length} skills {activeGroup === g.title ? '▲' : '▼'}
                </span>
              </div>

              {/* Expanded skills */}
              {activeGroup === g.title && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                  {g.skills.map(s => (
                    <span key={s} style={{
                      padding: '3px 10px',
                      fontSize: 11,
                      background: `${g.accent}12`,
                      color: g.accent,
                      border: `1px solid ${g.accent}40`,
                      fontWeight: 'bold',
                    }}>{s}</span>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <p style={{ fontSize: 10, color: '#bbb', textAlign: 'center' }}>
        Click any category to expand skills
      </p>
    </div>
  );
};

export default Skills;
